// Calculate date range for last 7 days
const now = new Date();
const weekEnd = now.toISOString().split('T')[0];
const weekStart = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

// Unix timestamps for GHL API
const startTimestamp = Math.floor(new Date(weekStart).getTime() / 1000);
const endTimestamp = Math.floor(now.getTime() / 1000);

return [{
  json: {
    weekStart,
    weekEnd,
    startTimestamp,
    endTimestamp
  }
}];

// Compile stats from all API responses
const items = $input.all();

// Parse contacts
const contactsData = items[0]?.json?.body?.contacts || items[0]?.json?.data?.contacts || [];
const newLeadsCount = Array.isArray(contactsData) ? contactsData.length : 0;

// Parse opportunities
const oppsData = items[1]?.json?.body?.opportunities || items[1]?.json?.data?.opportunities || [];
const opportunitiesByStage = {};
if (Array.isArray(oppsData)) {
  oppsData.forEach(opp => {
    const stage = opp.pipelineStageId || opp.stage || 'Unknown';
    opportunitiesByStage[stage] = (opportunitiesByStage[stage] || 0) + 1;
  });
}

// Parse conversations
const convsData = items[2]?.json?.body?.conversations || items[2]?.json?.data?.conversations || [];
let callsMade = 0;
let messagesSent = 0;
if (Array.isArray(convsData)) {
  convsData.forEach(conv => {
    if (conv.type === 'CALL' || conv.type === 'call') callsMade++;
    if (conv.type === 'SMS' || conv.type === 'sms' || conv.type === 'EMAIL' || conv.type === 'email') messagesSent++;
  });
}

// Date range
const dateRange = items[0]?.json?.weekStart 
  ? `${items[0].json.weekStart} to ${items[0].json.weekEnd}`
  : 'Last 7 days';

const weekStart = items[0]?.json?.weekStart || new Date(Date.now() - 7*24*60*60*1000).toISOString().split('T')[0];
const weekEnd = items[0]?.json?.weekEnd || new Date().toISOString().split('T')[0];

// Build stage summary HTML
let stageRows = '';
for (const [stage, count] of Object.entries(opportunitiesByStage)) {
  stageRows += `<tr><td style="padding:10px 16px;border-bottom:1px solid #eee;">${stage}</td><td style="padding:10px 16px;border-bottom:1px solid #eee;text-align:center;font-weight:700;">${count}</td></tr>`;
}
if (!stageRows) {
  stageRows = '<tr><td colspan="2" style="padding:10px 16px;color:#999;">No pipeline activity this week</td></tr>';
}

const totalOpps = Array.isArray(oppsData) ? oppsData.length : 0;

return [{
  json: {
    newLeadsCount,
    totalOpportunities: totalOpps,
    opportunitiesByStage,
    callsMade,
    messagesSent,
    weekStart,
    weekEnd,
    stageRows,
    dateRange
  }
}];

// Extract client emails for simplified report
const contacts = $input.first().json.contacts || $input.first().json.data?.contacts || [];
const clients = contacts.filter(c => c.email).map(c => ({
  json: {
    email: c.email,
    firstName: c.firstName || c.name?.split(' ')[0] || 'there',
    weekStart: $('Compile Stats').first().json.weekStart,
    weekEnd: $('Compile Stats').first().json.weekEnd,
    newLeadsCount: $('Compile Stats').first().json.newLeadsCount,
    totalOpportunities: $('Compile Stats').first().json.totalOpportunities
  }
}));
return clients;
